#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int A[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &A[i]);
        }
        int L = 1;
        int *lengths = (int*)malloc(n * sizeof(int));
        int *counts = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            lengths[i] = 1;
            counts[i] = 1;
        }
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (A[i] > A[j] && lengths[i] < lengths[j] + 1) {
                    lengths[i] = lengths[j] + 1;
                    counts[i] = counts[j];
                } else if (A[i] > A[j] && lengths[i] == lengths[j] + 1) {
                    counts[i] = (counts[i] + counts[j]) % MOD;
                }
            }
            L = (L > lengths[i]) ? L : lengths[i];
        }
        int answer = 0;
        for (int i = 0; i < n; i++) {
            if (lengths[i] == L - 1) {
                answer = (answer + counts[i]) % MOD;
            }
        }
        printf("%d\n", answer);
        free(lengths);
        free(counts);
    }
    return 0;
}

